// pages/Auth/Logout.jsx
import { useEffect } from "react";
import { useNavigate } from "react-router-dom";

const Logout = ({ setUserRole }) => {
  const navigate = useNavigate();

  useEffect(() => {
    setUserRole(null);
    navigate("/login");
  }, [setUserRole, navigate]);

  return null;
};

export default Logout;
